import{_ as a,c as i,o as d,ag as s}from"./chunks/framework.QPV3Ar9-.js";const c=JSON.parse('{"title":"前言","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/podman/podman_precheck.md","filePath":"guide/podman/podman_precheck.md","lastUpdated":1772543014000}'),e={name:"guide/podman/podman_precheck.md"};function n(r,t,l,h,p,o){return d(),i("div",null,t[0]||(t[0]=[s('<h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h1><p>以下为非自定义部分的介绍，自定义部分有自己对应的介绍，勿弄混了</p><p>如果你的宿主机本身没有IPV6的子网又想给容器分配IPV6地址，需要宿主机本身已有公网IPV6地址，安装脚本会自动检测并配置</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Podman 方案<strong>不支持 KVM/QEMU 虚拟机</strong>，仅支持 Linux 容器（LXC），适用于无 KVM 硬件虚拟化支持的环境。</p></div><p>欢迎给项目一个 <code>Star</code> 进行免费的支持--&gt;<a href="https://github.com/oneclickvirt/podman" target="_blank" rel="noreferrer">https://github.com/oneclickvirt/podman</a></p><h2 id="项目特点" tabindex="-1">项目特点 <a class="header-anchor" href="#项目特点" aria-label="Permalink to &quot;项目特点&quot;">​</a></h2><p>基于 Podman（daemonless 架构）运行时，通过批量或单独开设 NAT 服务器</p><ul><li>使用各发行版官方软件包安装 Podman（无守护进程，daemonless 架构）</li><li>使用本仓库自编译的基础镜像（存储在 GitHub Releases），优先离线加载，无法获取时回退到 ghcr.io 镜像</li><li>每个容器自带 1 个外网 SSH 端口，25 个内外网一致端口，可选择是否绑定独立 IPV6 地址</li><li>支持 lxcfs 挂载（若宿主机安装了 lxcfs），提供容器内真实 /proc 视图</li><li>原生支持 rootless（本方案使用 root 运行以简化网络配置）</li><li>支持国内 CDN 镜像加速</li></ul><h2 id="支持的系统" tabindex="-1">支持的系统 <a class="header-anchor" href="#支持的系统" aria-label="Permalink to &quot;支持的系统&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系统</th><th>amd64</th><th>arm64</th></tr></thead><tbody><tr><td>Ubuntu 22.04</td><td>✓</td><td>✓</td></tr><tr><td>Debian 12</td><td>✓</td><td>✓</td></tr><tr><td>Alpine latest</td><td>✓</td><td>✓</td></tr><tr><td>AlmaLinux 9</td><td>✓</td><td>✓</td></tr><tr><td>RockyLinux 9</td><td>✓</td><td>✓</td></tr><tr><td>OpenEuler 22.03</td><td>✓</td><td>✓</td></tr></tbody></table><h2 id="配置要求" tabindex="-1">配置要求 <a class="header-anchor" href="#配置要求" aria-label="Permalink to &quot;配置要求&quot;">​</a></h2><ul><li>宿主机系统：Ubuntu、Debian、RockyLinux 9+、AlmaLinux 9+、CentOS 9+、Alpine、Arch</li><li>架构：x86_64（amd64）或 ARM64</li><li>内核需支持 overlay 文件系统</li><li>网络能连接 Github 的 raw 界面即可</li><li>空闲硬盘有 3G 以上即可</li><li><strong>不需要 KVM 硬件支持</strong></li></ul><h2 id="与-containerd-和-docker-对比" tabindex="-1">与 containerd 和 docker 对比 <a class="header-anchor" href="#与-containerd-和-docker-对比" aria-label="Permalink to &quot;与 containerd 和 docker 对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>podman（本项目）</th><th>containerd</th><th>docker</th></tr></thead><tbody><tr><td>守护进程</td><td>无（daemonless）</td><td>轻量级 containerd</td><td>重量级 Docker daemon</td></tr><tr><td>运行时</td><td>crun/runc</td><td>runc</td><td>runc</td></tr><tr><td>管理命令</td><td>podman</td><td>nerdctl</td><td>docker</td></tr><tr><td>rootless 支持</td><td>原生支持</td><td>需配置</td><td>需配置</td></tr><tr><td>镜像格式</td><td>OCI</td><td>OCI</td><td>OCI</td></tr><tr><td>网络后端</td><td>netavark/CNI</td><td>CNI</td><td>Docker bridge</td></tr><tr><td>容器支持</td><td>Linux 容器（LXC）</td><td>Linux 容器（LXC）</td><td>Linux 容器 + KVM 虚拟机</td></tr><tr><td>安装方式</td><td>系统包管理器</td><td>nerdctl-full bundle</td><td>Docker 官方脚本</td></tr></tbody></table><p>推荐在开设 NAT 服务器前先增加部分 SWAP 虚拟内存，避免突发的内存占用导致宿主机卡死</p><p>国际</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/spiritLHLS/addswap/main/addswap.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>国内</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://cdn.spiritlhl.net/https://raw.githubusercontent.com/spiritLHLS/addswap/main/addswap.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addswap.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',19)]))}const u=a(e,[["render",n]]);export{c as __pageData,u as default};
